"use client";

import { useSearchParams } from "next/navigation";
import Link from "next/link";
import { Button } from "@/components/ui/button";


type ResultData = {
  level: string;
  color: string;
  bg: string;
  icon: string;
  message: string;
  tips: string[];
};

export default function ResultPage() {
  const searchParams = useSearchParams();
  const scoreParam = searchParams.get("score");
  const score = Number(scoreParam);

  // Validate score
  const safeScore = [0, 1, 2].includes(score) ? score : 0;

  const results: Record<number, ResultData> = {
    0: {
      level: "Normal Stress Level",
      color: "text-green-600",
      bg: "from-green-100 to-green-50",
      icon: "🧘‍♂️",
      message:
        "Your stress levels appear balanced. Keep maintaining healthy habits!",
      tips: [
        "Continue practicing mindfulness or meditation.",
        "Maintain your sleep, diet, and hydration routine.",
        "Engage in relaxing hobbies or calm activities.",
      ],
    },
    1: {
      level: "Moderate Stress Level",
      color: "text-yellow-600",
      bg: "from-yellow-100 to-yellow-50",
      icon: "😐",
      message:
        "You may be experiencing mild to moderate stress. A little care can help restore balance.",
      tips: [
        "Take short breaks during study or work.",
        "Practice breathing exercises when you feel tense.",
        "Talk to friends, family, or someone you trust.",
      ],
    },
    2: {
      level: "High Stress Level",
      color: "text-red-600",
      bg: "from-red-100 to-red-50",
      icon: "⚠️",
      message:
        "Your stress levels appear high. Consider seeking guidance or professional support.",
      tips: [
        "Reach out to a mental health professional.",
        "Avoid stressful environments if possible.",
        "Engage in grounding or calming exercises.",
      ],
    },
  };

  const r = results[safeScore];

  // ------------------- UI -------------------
  return (
    <div className="min-h-screen bg-gradient-to-b from-blue-50 to-white flex flex-col items-center py-20 px-6">

      <div className={`w-28 h-28 rounded-full flex items-center justify-center text-5xl shadow-lg bg-gradient-to-b ${r.bg} mb-6`}>
        {r.icon}
      </div>

      <h1 className="text-4xl font-bold text-gray-800 mb-2">
        Stress Assessment Result
      </h1>

      <h2 className={`text-2xl font-semibold mt-2 mb-4 ${r.color}`}>
        {r.level}
      </h2>

      <p className="text-gray-600 text-center max-w-xl mb-10 leading-relaxed">
        {r.message}
      </p>

      {/* Progress Circle */}
      <div className="relative flex items-center justify-center mb-10">
        <svg className="w-40 h-40 rotate-[-90deg]">
          <circle
            cx="80"
            cy="80"
            r="70"
            stroke="#e5e7eb"
            strokeWidth="12"
            fill="transparent"
          />
          <circle
            cx="80"
            cy="80"
            r="70"
            stroke={safeScore === 2 ? "#dc2626" : safeScore === 1 ? "#facc15" : "#16a34a"}
            strokeWidth="12"
            fill="transparent"
            strokeDasharray="440"
            strokeDashoffset={440 - (safeScore + 1) * 145}
            strokeLinecap="round"
          />
        </svg>
        <span className="absolute text-xl font-semibold text-gray-700">
          Level {safeScore}
        </span>
      </div>

      {/* Tips Box */}
      <div className="bg-white shadow-xl border border-gray-200 w-full max-w-xl p-8 rounded-2xl mb-10">
        <h3 className="text-xl font-bold text-center mb-4 text-gray-800">
          Recommended Next Steps
        </h3>

        <ul className="space-y-3 text-gray-700 text-base leading-relaxed">
          {r.tips.map((tip, idx) => (
            <li key={idx} className="flex items-start gap-2">
              <span className="text-blue-600 text-lg">•</span>
              <span>{tip}</span>
            </li>
          ))}
        </ul>
      </div>

      <div className="flex gap-4">
        <Link href="/resources">
          <Button className="bg-blue-600 text-white hover:bg-blue-700 px-6 py-3 rounded-full text-base">
            View Resources
          </Button>
        </Link>

        <Link href="/">
          <Button className="bg-lime-400 text-gray-900 hover:bg-lime-500 px-6 py-3 rounded-full text-base">
            Back to Home
          </Button>
        </Link>
      </div>
    </div>
  );
}
